const fills = $('Fetch Broker Fills').all().map(i => i.json).filter(f => f && f.order_id);
const rows = $input.all().map(i => i.json).filter(r => r && r.id);
const esc = (s) => s == null ? '' : String(s).replace(/'/g, "''");
const known = new Set();
for (const r of rows) {
  if (r.entry_order_id) known.add(r.entry_order_id);
  if (r.exit_order_id) known.add(r.exit_order_id);
}
const orphans = fills.filter(f => !known.has(f.order_id));
const now = Date.now();
const stale = rows.filter(r => r.status === 'open' && r.entry_fill_price && r.entry_fill_time && (now - new Date(r.entry_fill_time).getTime()) > 2 * 86400000);
const mismatches = orphans.length + stale.length;
const summary = 'reconciliation: ' + fills.length + ' broker fills, ' + orphans.length + ' orphan fills, ' + stale.length + ' stale open rows';
const raw = JSON.stringify({ orphan_fills: orphans.slice(0, 20), stale_row_ids: stale.map(r => r.id) }).split('$qet$').join('');
const audit_sql = "INSERT INTO public.audit_log (user_id, workflow_name, execution_id, mode, decision, reason, raw) VALUES (NULL, 'qet-h5-reconciliation', '" + esc($execution.id) + "', 'paper', '" + (mismatches ? 'errored' : 'skipped') + "', '" + esc(summary) + "', $qet$" + raw + "$qet$::jsonb)";
return [{ json: { mismatches: mismatches, text: '[QET H5 ALERT] ' + summary, audit_sql: audit_sql } }];

const rows = $input.all().map(i => i.json);
let text = '[QET WEEKLY EDGE REPORT]';
for (const r of rows) {
  text += '\n' + r.strategy + ' (' + r.mode + '): n=' + r.n_trades + ' | W=' + r.win_rate + ' | E[R]=' + r.expectancy_r + ' | PF=' + (r.profit_factor == null ? '-' : r.profit_factor) + ' | t=' + (r.t_stat == null ? '-' : r.t_stat) + ' | Sharpe=' + (r.sharpe_annualized == null ? '-' : r.sharpe_annualized) + ' | f*=' + (r.kelly_star == null ? '-' : r.kelly_star) + ' | slip=' + r.entry_slip + '/' + r.exit_slip + 'bps | net=' + r.net_pnl;
}
text += '\n\nRatchet rule: no sizing change except in response to these numbers.';
return [{ json: { text: text } }];
